    }
    $info{files} = \%files;
    return \%info;
}

sub cmd_diff {
    my ($hash1, $hash2) = @_;
    my $c1 = parse_commit($hash1);
    unless ($c1) {
        print "Invalid commit\n";
        exit 1;
    }
    my $c2 = parse_commit($hash2);
    unless ($c2) {
        print "Invalid commit\n";
        exit 1;
    }

    my %f1 = %{$c1->{files}};
    my %f2 = %{$c2->{files}};

    my %all;
    $all{$_} = 1 for keys %f1;
    $all{$_} = 1 for keys %f2;

    for my $fname (sort keys %all) {
        if (!exists $f1{$fname}) {
            print "Added: $fname\n";
        } elsif (!exists $f2{$fname}) {
            print "Removed: $fname\n";
        } elsif ($f1{$fname} ne $f2{$fname}) {
            print "Modified: $fname\n";
        }
    }
}

sub cmd_checkout {
    my ($hash) = @_;
    my $c = parse_commit($hash);
    unless ($c) {
        print "Invalid commit\n";
        exit 1;
    }

    my %files = %{$c->{files}};
    for my $fname (sort keys %files) {
        my $blob = "$OBJECTS_DIR/$files{$fname}";
        open(my $in, '<:raw', $blob) or die "Cannot read blob: $!\n";
        my $content = do { local $/; <$in> };
        close($in);
        open(my $out, '>:raw', $fname) or die "Cannot write $fname: $!\n";
        print $out $content;
        close($out);
    }

    # Update HEAD
    open(my $fh, '>', $HEAD_FILE) or die "Cannot write HEAD: $!\n";
    print $fh $hash;
    close($fh);

    # Clear index
    open($fh, '>', $INDEX_FILE) or die "Cannot clear index: $!\n";
    close($fh);

    print "Checked out $hash\n";
}

sub cmd_reset {
    my ($hash) = @_;
    unless (-f "$COMMITS_DIR/$hash") {
        print "Invalid commit\n";
        exit 1;
    }

    # Update HEAD
    open(my $fh, '>', $HEAD_FILE) or die "Cannot write HEAD: $!\n";
    print $fh $hash;
    close($fh);

    # Clear index
    open($fh, '>', $INDEX_FILE) or die "Cannot clear index: $!\n";
    close($fh);

    print "Reset to $hash\n";
}

sub cmd_rm {
    my ($filename) = @_;
    my @entries;
    if (-f $INDEX_FILE) {
        open(my $fh, '<', $INDEX_FILE) or die "Cannot read index: $!\n";
        @entries = <$fh>;
        chomp @entries;
        close($fh);
        @entries = grep { $_ ne '' } @entries;
    }

    unless (grep { $_ eq $filename } @entries) {
        print "File not in index\n";
        exit 1;
    }

    @entries = grep { $_ ne $filename } @entries;

    open(my $fh, '>', $INDEX_FILE) or die "Cannot write index: $!\n";
    print $fh "$_\n" for @entries;
    close($fh);
}

sub cmd_show {
    my ($hash) = @_;
    my $c = parse_commit($hash);
    unless ($c) {
        print "Invalid commit\n";
        exit 1;
    }

    print "commit $hash\n";
    print "Date: $c->{timestamp}\n";
    print "Message: $c->{message}\n";
    print "Files:\n";
    my %files = %{$c->{files}};
    for my $fname (sort keys %files) {
        print "  $fname $files{$fname}\n";
    }
}

# Main
my $cmd = shift @ARGV // '';

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    my $file = shift @ARGV;
    cmd_add($file);
} elsif ($cmd eq 'commit') {
    my $flag = shift @ARGV // '';
    my $message = shift @ARGV // '';
    if ($flag ne '-m' || $message eq '') {
        print "Usage: minigit commit -m \"<message>\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($cmd eq 'log') {
    cmd_log();
} elsif ($cmd eq 'status') {
    cmd_status();
} elsif ($cmd eq 'diff') {
    my $h1 = shift @ARGV // '';
    my $h2 = shift @ARGV // '';
    cmd_diff($h1, $h2);
} elsif ($cmd eq 'checkout') {
    my $hash = shift @ARGV // '';
    cmd_checkout($hash);
} elsif ($cmd eq 'reset') {
    my $hash = shift @ARGV // '';
    cmd_reset($hash);
} elsif ($cmd eq 'rm') {
    my $file = shift @ARGV // '';
    cmd_rm($file);
} elsif ($cmd eq 'show') {
    my $hash = shift @ARGV // '';
    cmd_show($hash);
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}

