#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Basename;
use Cwd qw(getcwd);

my $MINIGIT_DIR = '.minigit';
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $COMMITS_DIR = "$MINIGIT_DIR/commits";
my $INDEX_FILE  = "$MINIGIT_DIR/index";
my $HEAD_FILE   = "$MINIGIT_DIR/HEAD";

sub minihash {
    my ($data) = @_;
    my $h = 1469598103934665603;
    {
        use integer;
        for my $b (unpack('C*', $data)) {
            $h ^= $b;
            $h *= 1099511628211;
        }
    }
    # Convert signed to unsigned for formatting
    no warnings 'portable';
    return sprintf('%016x', $h < 0 ? $h + 18446744073709551616 : $h);
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path($OBJECTS_DIR);
    make_path($COMMITS_DIR);
    open(my $fh, '>', $INDEX_FILE) or die "Cannot create index: $!\n";
    close($fh);
    open($fh, '>', $HEAD_FILE) or die "Cannot create HEAD: $!\n";
    close($fh);
}

sub cmd_add {
    my ($filename) = @_;
    unless (defined $filename && -e $filename) {
        print "File not found\n";
        exit 1;
    }

    # Read file content
    open(my $fh, '<:raw', $filename) or die "Cannot read $filename: $!\n";
    my $content = do { local $/; <$fh> };
    close($fh);

    my $hash = minihash($content);

    # Store blob
    open($fh, '>:raw', "$OBJECTS_DIR/$hash") or die "Cannot write object: $!\n";
    print $fh $content;
    close($fh);

    # Read current index
    my @entries;
    if (-f $INDEX_FILE) {
        open($fh, '<', $INDEX_FILE) or die "Cannot read index: $!\n";
        @entries = <$fh>;
        chomp @entries;
        close($fh);
        @entries = grep { $_ ne '' } @entries;
    }

    # Add if not already present
    unless (grep { $_ eq $filename } @entries) {
        push @entries, $filename;
    }

    # Write index
    open($fh, '>', $INDEX_FILE) or die "Cannot write index: $!\n";
    print $fh "$_\n" for @entries;
    close($fh);
}

sub cmd_commit {
    my ($message) = @_;

    # Read index
    my @entries;
    if (-f $INDEX_FILE) {
        open(my $fh, '<', $INDEX_FILE) or die "Cannot read index: $!\n";
        @entries = <$fh>;
        chomp @entries;
        close($fh);
        @entries = grep { $_ ne '' } @entries;
    }

    if (!@entries) {
        print "Nothing to commit\n";
        exit 1;
    }

    # Read HEAD
    my $parent = '';
    if (-f $HEAD_FILE) {
        open(my $fh, '<', $HEAD_FILE) or die "Cannot read HEAD: $!\n";
        $parent = <$fh> // '';
        chomp $parent;
        close($fh);
    }
    $parent = 'NONE' if $parent eq '';

    my $timestamp = time();

    # Sort filenames
    my @sorted = sort @entries;

    # Build file list with blob hashes
    my @file_lines;
    for my $fname (@sorted) {
        # Read the file and compute hash
        open(my $fh, '<:raw', $fname) or die "Cannot read $fname: $!\n";
        my $content = do { local $/; <$fh> };
        close($fh);
        my $hash = minihash($content);
        push @file_lines, "$fname $hash";
    }

    # Build commit content
    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    $commit_content .= join("\n", @file_lines) . "\n";

    my $commit_hash = minihash($commit_content);

    # Write commit file
    open(my $fh, '>', "$COMMITS_DIR/$commit_hash") or die "Cannot write commit: $!\n";
    print $fh $commit_content;
    close($fh);

    # Update HEAD
    open($fh, '>', $HEAD_FILE) or die "Cannot write HEAD: $!\n";
    print $fh $commit_hash;
    close($fh);

    # Clear index
    open($fh, '>', $INDEX_FILE) or die "Cannot clear index: $!\n";
    close($fh);

    print "Committed $commit_hash\n";
}

sub cmd_log {
    # Read HEAD
    my $current = '';
    if (-f $HEAD_FILE) {
        open(my $fh, '<', $HEAD_FILE) or die "Cannot read HEAD: $!\n";
        $current = <$fh> // '';
        chomp $current;
        close($fh);
    }

    if ($current eq '') {
        print "No commits\n";
        return;
    }

    my $first = 1;
    while ($current ne '' && $current ne 'NONE') {
        my $commit_file = "$COMMITS_DIR/$current";
        last unless -f $commit_file;

        open(my $fh, '<', $commit_file) or die "Cannot read commit: $!\n";
        my @lines = <$fh>;
        chomp @lines;
        close($fh);

        my ($parent, $timestamp, $message);
        for my $line (@lines) {
            if ($line =~ /^parent: (.*)$/) {
                $parent = $1;
            } elsif ($line =~ /^timestamp: (.*)$/) {
                $timestamp = $1;
            } elsif ($line =~ /^message: (.*)$/) {
                $message = $1;
            }
        }

        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";

        $first = 0;
        $current = ($parent eq 'NONE') ? '' : $parent;
    }
}

# Main
my $cmd = shift @ARGV // '';

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    my $file = shift @ARGV;
    cmd_add($file);
} elsif ($cmd eq 'commit') {
    # Parse -m "message"
    my $flag = shift @ARGV // '';
    my $message = shift @ARGV // '';
    if ($flag ne '-m' || $message eq '') {
        print "Usage: minigit commit -m \"<message>\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($cmd eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}
